#include<iostream>#include<algorithm>#include<string>#define ll long longusing namespace std;int main(){    ll n;    cin>>n;    string s;    cin>>s;    int index_1=-1,index_2=-1;    for(ll i=0;i<n-1;i++){        if(s[i]>s[i+1]){            index_1=i+1;            index_2=i+2;            break;        }            }    if(index_1==-1){        cout<<"no\n";    }    else{       cout<<"yes\n";        cout<<index_1<<" "<<index_2<<"\n";    }}